using BgCommon.Script.Runtime.Configuration;using BgCommon.Script.Runtime.Utilities;namespace BgCommon.Script.Runtime.DotNet;public class DotNetInfo : IDotNetInfo{    private static readonly object DotNetRuntimeVersionsLocateLock = new();    private static readonly string DotNetExeName = PlatformUtil.IsOSWindows() ? "dotnet.exe" : "dotnet";    private static readonly object DotNetSdkVersionsLocateLock = new();    private readonly DotNetEnvironment environment = new();    private readonly DotNetCliRunner dotNetCliRunner = new();    private readonly DotNetPathResolver dotNetPathResolver = new();    private readonly IApplicationSettingsValues settings;    private readonly object dotNetRootDirLocateLock = new();    private readonly object dotNetExeLocateLock = new();    private readonly object dotNetEfToolExeLocateLock = new();    private static DotNetRuntimeVersion[]? dotNetRuntimeVersions;    private static DotNetSdkVersion[]? dotNetSdkVersions;    private string? dotNetRootDirPath;    private string? dotNetExecutablePath;    private string? dotNetEfToolPath;    public DotNetInfo(IApplicationSettings settings)    {        this.settings = settings.Values;    }    /// <summary>    /// Returns the version of the .NET runtime used in the current app domain.    /// </summary>    public SemanticVersion GetCurrentDotNetRuntimeVersion() => environment.GetCurrentDotNetRuntimeVersion();    public string LocateDotNetRootDirectoryOrThrow()    {        return LocateDotNetRootDirectory() ?? throw new Exception("Could not find the dotnet ROOT directory.");    }    public string? LocateDotNetRootDirectory()    {        if (!string.IsNullOrEmpty(dotNetRootDirPath))        {            return dotNetRootDirPath;        }        lock (dotNetRootDirLocateLock)        {            if (dotNetRootDirPath != null)            {                return dotNetRootDirPath;            }            var report = dotNetPathResolver.FindDotNetInstallDir(settings);            if (report.ResolvedPath is not null)            {                System.Environment.SetEnvironmentVariable("DOTNET_ROOT", report.ResolvedPath.Path);            }            dotNetRootDirPath = report.ResolvedPath?.Path;        }        return dotNetRootDirPath;    }    public string LocateDotNetExecutableOrThrow()    {        var path = LocateDotNetExecutable();        if (path != null)        {            return path;        }        throw new FileNotFoundException(            $"Could not find the '{DotNetExeName}' executable. " +            $"Verify that '{DotNetExeName}' is in your PATH, or ensure the 'DOTNET_ROOT' environment variable is set.");    }    public string? LocateDotNetExecutable()    {        if (!string.IsNullOrEmpty(dotNetExecutablePath))        {            return dotNetExecutablePath;        }        lock (dotNetExeLocateLock)        {            if (dotNetExecutablePath != null)            {                return dotNetExecutablePath;            }            string? exePath = null;            var rootDirPath = LocateDotNetRootDirectory();            if (DotNetPathResolver.IsValidDotNetSdkRootDirectory(rootDirPath))            {                exePath = Path.Combine(rootDirPath!, DotNetExeName);            }            dotNetExecutablePath = exePath;        }        return dotNetExecutablePath;    }    public DotNetRuntimeVersion[] GetDotNetRuntimeVersionsOrThrow()    {        var versions = GetDotNetRuntimeVersions();        return versions.Length > 0            ? versions            : throw new Exception("Could not find any .NET runtimes");    }    public DotNetRuntimeVersion[] GetDotNetRuntimeVersions()    {        if (dotNetRuntimeVersions != null && dotNetRuntimeVersions.Length > 0)        {            return dotNetRuntimeVersions;        }        lock (DotNetRuntimeVersionsLocateLock)        {            if (dotNetRuntimeVersions != null && dotNetRuntimeVersions.Length > 0)            {                return dotNetRuntimeVersions;            }            var dotNetExePath = LocateDotNetExecutable();            if (dotNetExePath == null)            {                return [];            }            var output = this.dotNetCliRunner.ExecuteCommand(dotNetExePath, "--list-runtimes");            dotNetRuntimeVersions = output.Split(Environment.NewLine)                .Select(l => l.Trim().Split(" ", StringSplitOptions.RemoveEmptyEntries).Take(2).Select(x => x.Trim()).ToArray())                .Where(a => a.Length == 2 && a.All(x => x.Length > 0))                .Select(a => SemanticVersion.TryParse(a[1], out var version) ? new DotNetRuntimeVersion(a[0], version) : null)                .Where(v => v != null)                .ToArray()!;        }        return dotNetRuntimeVersions;    }    public DotNetSdkVersion[] GetDotNetSdkVersionsOrThrow()    {        var versions = GetDotNetSdkVersions();        return versions.Length > 0            ? versions            : throw new Exception("Could not find any .NET SDKs");    }    public DotNetSdkVersion[] GetDotNetSdkVersions()    {        if (dotNetSdkVersions != null && dotNetSdkVersions.Length > 0)        {            return dotNetSdkVersions;        }        lock (DotNetSdkVersionsLocateLock)        {            if (dotNetSdkVersions != null && dotNetSdkVersions.Length > 0)            {                return dotNetSdkVersions;            }            var dotNetExePath = LocateDotNetExecutable();            if (dotNetExePath == null)            {                return [];            }            var output = this.dotNetCliRunner.ExecuteCommand(dotNetExePath, "--list-sdks");            dotNetSdkVersions = output.Split(Environment.NewLine)                .Select(l => l.Split(" ")[0].Trim())                .Where(v => !string.IsNullOrWhiteSpace(v))                .Select(v => SemanticVersion.TryParse(v, out var version) ? new DotNetSdkVersion(version) : null)                .Where(x => x is not null)                .ToArray()!;        }        return dotNetSdkVersions;    }    public DotNetSdkVersion GetLatestSupportedDotNetSdkVersionOrThrow(bool includePrerelease = false)    {        var latestSupported = GetLatestSupportedDotNetSdkVersion(includePrerelease);        return latestSupported ?? throw new Exception("Could not find any supported .NET SDKs");    }    public DotNetSdkVersion? GetLatestSupportedDotNetSdkVersion(bool includePrerelease = false)    {        return GetDotNetSdkVersions()            .Where(v => v.IsSupported() && (includePrerelease || !v.Version.IsPrerelease))            .MaxBy(x => x.Version);    }    public string LocateDotNetEfToolExecutableOrThrow()    {        var path = LocateDotNetEfToolExecutable();        if (path != null)        {            return path;        }        var exeName = GetDotNetEfToolExeName();        throw new Exception(            $"Could not find the '{exeName}' executable. " +            $"Verify that '{exeName}' is in your PATH, or ensure the that you have it installed in " +            "the dotnet global tools path under '{UserHomeDirectory}/.dotnet/tools'.");    }    public string? LocateDotNetEfToolExecutable()    {        if (dotNetEfToolPath != null)        {            return dotNetEfToolPath;        }        lock (dotNetEfToolExeLocateLock)        {            if (dotNetEfToolPath != null)            {                return dotNetEfToolPath;            }            string? path = null;            var exeName = GetDotNetEfToolExeName();            try            {                // Try getting path using ShellExecute                // Prioritize this over global tool install path in case user defines a different path for dotnet for the execution of this app.                using var process = Process.Start(new ProcessStartInfo                {                    UseShellExecute = true,                    CreateNoWindow = true,                    WindowStyle = ProcessWindowStyle.Hidden,                    FileName = exeName,                    Arguments = "--version",                    RedirectStandardOutput = true,                }.CopyCurrentEnvironmentVariables());                path = process?.MainModule?.FileName;                // Process file path could sometimes point to the shell that executed the command, ex: if ShellExecute could find the command                if (path?.EndsWith(exeName) != true)                {                    path = null;                }            }            catch            {                // if it failed, it wasn't found            }            if (string.IsNullOrWhiteSpace(path))            {                // Try getting path from global tool install path                var globalToolInstallPath = Path.Combine(                    System.Environment.GetFolderPath(System.Environment.SpecialFolder.UserProfile),                    ".dotnet",                    "tools"                );                var testPath = Path.Combine(globalToolInstallPath, exeName);                if (File.Exists(testPath))                {                    path = testPath;                }            }            dotNetEfToolPath = path;        }        return dotNetEfToolPath;    }    public SemanticVersion? GetDotNetEfToolVersion(string dotNetEfToolExePath)    {        var output = this.dotNetCliRunner.ExecuteCommand(dotNetEfToolExePath, "--version");        return SemanticVersion.TryParse(output.Split(Environment.NewLine).Skip(1).FirstOrDefault(), out var version)            ? version            : null;    }    private static string GetDotNetEfToolExeName()    {        return PlatformUtil.IsOSWindows() ? "dotnet-ef.exe" : "dotnet-ef";    }    /// <inheritdoc/>    public override bool Equals(object? obj)    {        return obj is DotNetInfo info &&               EqualityComparer<object>.Default.Equals(dotNetEfToolExeLocateLock, info.dotNetEfToolExeLocateLock);    }}